def average(values):
    """Retourne la moyenne arithmétique d'une liste."""
    if not values:
        return 0.0
    return sum(values) / len(values)

def find_first(predicate, iterable, default=None):
    """Retourne le premier élément satisfaisant predicate, ou default."""
    for item in iterable:
        if predicate(item):
            return item
    return default

def parse_authority(authority):
    """Parse a 'user:pass@host:port' authority string."""
    userinfo, sep, hostport = authority.rpartition('@')
    if sep:
        if ':' in userinfo:
            user, _, password = userinfo.partition(':')
        else:
            user, password = userinfo, None
    else:
        user, password = None, None
        hostport = authority
    if hostport.startswith('['):
        end = hostport.find(']')
        if end == -1:
            raise ValueError('Invalid IPv6 host')
        host = hostport[1:end]
        rest = hostport[end + 1:]
        port = rest[1:] if rest.startswith(':') else None
    elif ':' in hostport:
        host, _, port = hostport.rpartition(':')
    else:
        host, port = hostport, None
    return user, password, host, port

def validate(data, schema):
    errors = []
    for key, rule in schema.items():
        if key not in data:
            if rule.get('required'):
                errors.append(f'{key} is required')
            continue
        value = data[key]
        expected_type = rule.get('type')
        if expected_type:
            if not isinstance(value, expected_type):
                errors.append(f'{key} has wrong type')
                continue
        if 'min' in rule:
            if isinstance(value, (int, float)):
                if value < rule['min']:
                    errors.append(f'{key} below min')
            elif isinstance(value, str):
                if len(value) < rule['min']:
                    errors.append(f'{key} too short')
            elif isinstance(value, list):
                if len(value) < rule['min']:
                    errors.append(f'{key} list too short')
        if 'choices' in rule:
            if value not in rule['choices']:
                errors.append(f'{key} not in choices')
    return errors

def tokenize(source):
    tokens = []
    i = 0
    n = len(source)
    while i < n:
        c = source[i]
        if c.isspace():
            i += 1
            continue
        if c.isalpha() or c == '_':
            start = i
            while i < n and (source[i].isalnum() or source[i] == '_'):
                i += 1
            tokens.append(('IDENT', source[start:i]))
        elif c.isdigit():
            start = i
            has_dot = False
            while i < n and (source[i].isdigit() or (source[i] == '.' and not has_dot)):
                if source[i] == '.':
                    has_dot = True
                i += 1
            if has_dot:
                tokens.append(('FLOAT', float(source[start:i])))
            else:
                tokens.append(('INT', int(source[start:i])))
        elif c == '"':
            i += 1
            start = i
            while i < n and source[i] != '"':
                if source[i] == '\\':
                    i += 2
                else:
                    i += 1
            tokens.append(('STRING', source[start:i]))
            i += 1
        elif c in '+-*/=()':
            tokens.append(('OP', c))
            i += 1
        else:
            raise ValueError(f'Unexpected character {c!r} at {i}')
    return tokens

def f(a, b, c, d, e, g, h):
    r = 0
    s = 0
    t = 0
    if a > 0:
        for i in range(b):
            if c[i]:
                for j in range(d):
                    if e[j]:
                        if g[i][j]:
                            r += h * (a + b) * (c[i] - d) / (e[j] + 1)
                        elif h[i][j] < 0:
                            s -= a * b + c[i] * d - e[j]
                        else:
                            t += (a + b + c[i] + d + e[j] + g[i][j])
                    elif d > 0:
                        if c[i] > e[0]:
                            r += a * d
                        else:
                            s += b * d
            elif b > c[0]:
                t += a + b + c[0]
        for k in range(b):
            if c[k] and e[k]:
                r += g[k][0] * h[k][0]
                s -= g[k][0] - h[k][0]
                t *= (g[k][0] + h[k][0]) / (a + 1)
    return r + s + t

def gauss_eliminate(M, b):
    n = len(M)
    A = [row[:] + [bi] for row, bi in zip(M, b)]
    for i in range(n):
        max_row = i
        max_val = abs(A[i][i])
        for k in range(i + 1, n):
            if abs(A[k][i]) > max_val:
                max_val = abs(A[k][i])
                max_row = k
        if max_row != i:
            A[i], A[max_row] = A[max_row], A[i]
        if abs(A[i][i]) < 1e-12:
            for k in range(i + 1, n):
                if abs(A[k][i]) >= 1e-12:
                    for j in range(n + 1):
                        A[i][j], A[k][j] = A[k][j], A[i][j]
                    break
            else:
                raise ValueError('Singular matrix')
        for k in range(i + 1, n):
            factor = A[k][i] / A[i][i]
            for j in range(i, n + 1):
                A[k][j] -= factor * A[i][j]
            if abs(A[k][i]) > 1e-12:
                for m in range(i + 1, n):
                    if m != k:
                        f2 = A[m][i] / A[i][i]
                        for j in range(i, n + 1):
                            A[m][j] -= f2 * A[i][j]
    x = [0.0] * n
    for i in range(n - 1, -1, -1):
        s = A[i][n]
        for j in range(i + 1, n):
            s -= A[i][j] * x[j]
        x[i] = s / A[i][i]
    return x

def parse_color(value):
    """Parse une couleur exprimée en hex, rgb() ou nom."""
    if value.startswith('#'):
        return int(value[1:], 16)
    if value.startswith('rgb('):
        parts = value[4:-1].split(',')
        r, g, b = (int(p.strip()) for p in parts)
        return (r << 16) | (g << 8) | b
    named = {'red': 0xFF0000, 'green': 0x00FF00, 'blue': 0x0000FF}
    if value in named:
        return named[value]
    raise ValueError(f'unknown color: {value}')

def flatten_and_filter(matrix, threshold, normalize=False):
    """Aplatit une matrice 2D, filtre, et normalise optionnellement."""
    result = [
        v / threshold if normalize else v
        for row in matrix
        for v in row
        if v is not None and v >= threshold and (not normalize or threshold > 0)
    ]
    if not result:
        return []
    max_v = max(result)
    return [v / max_v if max_v > 0 else 0 for v in result]

import asyncio

async def execute_with_retry(operation, max_retries=3, backoff_base=2.0):
    """Exécute une opération async avec retry exponentiel."""
    last_error = None
    for attempt in range(max_retries):
        try:
            async with asyncio.timeout(10):
                result = await operation()
                if result is None:
                    raise ValueError('operation returned None')
                if isinstance(result, dict) and 'error' in result:
                    if result.get('retryable', False):
                        raise RuntimeError(result['error'])
                    return result
                return result
        except asyncio.TimeoutError as e:
            last_error = e
            if attempt < max_retries - 1:
                delay = backoff_base ** attempt
                await asyncio.sleep(delay)
                continue
            raise
        except (ValueError, RuntimeError) as e:
            last_error = e
            if attempt < max_retries - 1:
                delay = backoff_base ** attempt
                await asyncio.sleep(delay)
                continue
            raise
        except Exception:
            raise
    if last_error:
        raise last_error
    return None

from functools import wraps

def rate_limit(max_calls, period_seconds):
    """Décorateur qui limite le nombre d'appels par période."""
    def decorator(func):
        calls = []

        @wraps(func)
        def wrapper(*args, **kwargs):
            import time
            now = time.time()
            cutoff = now - period_seconds
            while calls and calls[0] < cutoff:
                calls.pop(0)
            if len(calls) >= max_calls:
                raise RuntimeError(f'rate limit: {max_calls} calls per {period_seconds}s')
            calls.append(now)
            return func(*args, **kwargs)

        return wrapper
    return decorator
